15	inline auto load_state(const std::string& path) -> HybridState
16	{
17	  std::ifstream f(path, std::ios::binary);
18	  if (!f)
19	    throw std::runtime_error("hybrid::load_state: cannot open " + path);
20	
21	  HybridState s{};
22	  f.read(reinterpret_cast<char*>(&s), sizeof(s));
23	  if (f.gcount() != static_cast<std::streamsize>(sizeof(s)))
24	    throw std::runtime_error("hybrid::load_state: short read on " + path);
25	
26	  if (s.magic != HYBRID_STATE_MAGIC)
27	    throw std::runtime_error("hybrid::load_state: bad magic in " + path);
28	  if (s.version != HYBRID_STATE_VERSION)
29	    throw std::runtime_error("hybrid::load_state: unsupported version in "
30	                             + path);
31	  return s;
32	}
