5	namespace hybrid {
6	
7	enum class AarSize : uint8_t
8	{
9	  Bits32 = 2,
10	  Bits64 = 3,
11	  Bits128 = 4,
12	};
13	
14	constexpr auto regno_csr(uint16_t csr) -> uint16_t { return csr; }
15	constexpr auto regno_gpr(uint16_t i) -> uint16_t { return 0x1000u + i; }
16	constexpr auto regno_fpr(uint16_t i) -> uint16_t { return 0x1020u + i; }
17	
18	// Builds a RISC-V Debug Module "Access Register" Abstract Command.
19	// cmdtype=0 (Access Register), transfer=1 (always do the transfer here).
20	constexpr auto access_register_command(uint16_t regno, AarSize size, bool write,
21	                                       bool postexec = false) -> uint32_t
22	{
23	  uint32_t cmd = 0;
24	  cmd |= (uint32_t(size) & 0x7u) << 20;
25	  if (postexec) cmd |= 1u << 18;
26	  cmd |= 1u << 17;  // transfer
27	  if (write) cmd |= 1u << 16;
28	  cmd |= regno;
29	  return cmd;
30	}
31	
32	}  // namespace hybrid
