1	// End-to-end smoke test for SystemCDmiBus.
2	//
3	// Builds a real Simulator (CPU + AHB DMI + Debug Module), loads spin.elf,
4	// and drives the live Debug Module synchronously via SystemCDmiBus. The
5	// test halts the CPU, round-trips x10 through DATA0/DATA1+COMMAND, and
6	// resumes. PASS/FAIL is reported on stderr and as the exit code.
7	
8	#include "cpu_config.hpp"
9	#include "hybrid/abstract_command.hpp"
10	#include "hybrid/resume_driver.hpp"
11	#include "hybrid/systemc_dmi_bus.hpp"
12	#include "platform/platform.hpp"
13	#include "simulator.hpp"
14	
15	#include <cci_configuration>
16	#include <spdlog/sinks/stdout_color_sinks.h>
17	#include <spdlog/spdlog.h>
18	#include <systemc>
19	
20	#include <cstdint>
21	#include <cstdio>
22	#include <cstdlib>
23	#include <stdexcept>
24	#include <string>
25	
26	namespace {
27	
28	using RD = hybrid::ResumeDriver;
29	
30	template<typename Bus>
31	auto poll_until(Bus& bus, uint8_t reg, uint32_t mask, bool want_set) -> bool
32	{
33	  for (unsigned i = 0; i < RD::kPollIterations; ++i) {
34	    const auto v = bus.read(reg);
35	    const bool is_set = (v & mask) == mask;
36	    if (is_set == want_set) return true;
37	  }
38	  return false;
39	}
40	
41	template<typename Cpu>
42	auto run_smoke(const std::string& elf_path) -> int
43	{
44	  Simulator<Cpu> sim{"sim"};
45	  sim.load_elf(elf_path);
46	
47	  sc_core::sc_start(sc_core::SC_ZERO_TIME);
48	  sim.reset();
49	
50	  using PLATFORM = ::Platform<platform_config<Cpu>>;
51	  hybrid::SystemCDmiBus<PLATFORM::dmi_addr_width, PLATFORM::dmi_data_width> bus{
52	    sim.platform.dmi, sim.platform.clk.period()};
53	
54	  spdlog::info("dmi_smoke: probing DMCONTROL.dmactive");
55	  bus.write(RD::kDmcontrol, RD::kDmcontrolDmactive);
56	  const auto dmcontrol = bus.read(RD::kDmcontrol);
57	  if ((dmcontrol & RD::kDmcontrolDmactive) == 0) {
58	    spdlog::error("dmi_smoke FAIL: dmactive did not stick (dmcontrol=0x{:08x})",
59	                  dmcontrol);
60	    return 1;
61	  }
62	
63	  spdlog::info("dmi_smoke: requesting halt");
64	  bus.write(RD::kDmcontrol, RD::kDmcontrolDmactive | RD::kDmcontrolHaltreq);
65	  if (!poll_until(bus, RD::kDmstatus, RD::kDmstatusAllhalted, /*want_set=*/true))
66	  {
67	    spdlog::error("dmi_smoke FAIL: did not reach allhalted within budget");
68	    return 2;
69	  }
70	  spdlog::info("dmi_smoke: halted");
71	
72	  // Round-trip a 64-bit pattern through x10 (a0).
73	  constexpr uint64_t pattern = 0xDEADBEEFCAFEBABEULL;
74	  const auto cmd_write =
75	    hybrid::access_register_command(hybrid::regno_gpr(10),
76	                                    hybrid::AarSize::Bits64,
77	                                    /*write=*/true);
78	  const auto cmd_read =
79	    hybrid::access_register_command(hybrid::regno_gpr(10),
80	                                    hybrid::AarSize::Bits64,
81	                                    /*write=*/false);
82	
83	  bus.write(RD::kData0, uint32_t(pattern & 0xFFFFFFFFu));
84	  bus.write(RD::kData1, uint32_t((pattern >> 32) & 0xFFFFFFFFu));
85	  bus.write(RD::kCommand, cmd_write);
86	  if (!poll_until(bus, RD::kAbstractcs, RD::kAbstractcsBusy, /*want_set=*/false))
87	  {
88	    spdlog::error("dmi_smoke FAIL: abstract write busy did not clear");
89	    return 3;
90	  }
91	
92	  bus.write(RD::kCommand, cmd_read);
93	  if (!poll_until(bus, RD::kAbstractcs, RD::kAbstractcsBusy, /*want_set=*/false))
94	  {
95	    spdlog::error("dmi_smoke FAIL: abstract read busy did not clear");
96	    return 4;
97	  }
98	  const uint64_t lo = bus.read(RD::kData0);
99	  const uint64_t hi = bus.read(RD::kData1);
100	  const uint64_t round = lo | (hi << 32);
101	  if (round != pattern) {
102	    spdlog::error("dmi_smoke FAIL: x10 readback 0x{:016x} != 0x{:016x}",
103	                  round, pattern);
104	    return 5;
105	  }
106	  spdlog::info("dmi_smoke: x10 round-trip OK");
107	
108	  spdlog::info("dmi_smoke: requesting resume");
109	  bus.write(RD::kDmcontrol, RD::kDmcontrolDmactive | RD::kDmcontrolResumereq);
110	  if (!poll_until(bus, RD::kDmstatus, RD::kDmstatusAllresumeack,
111	                  /*want_set=*/true)) {
112	    spdlog::error("dmi_smoke FAIL: did not reach allresumeack within budget");
113	    return 6;
114	  }
115	
116	  spdlog::info("dmi_smoke PASS");
117	  return 0;
118	}
119	
120	}  // namespace
121	
122	extern "C" auto sc_main(int argc, char* argv[]) -> int
123	try {
124	  spdlog::set_default_logger(spdlog::stderr_color_mt("stderr_logger"));
125	  spdlog::set_pattern("[%^%l%$] %v");
126	
127	  if (argc < 2) {
128	    std::fprintf(stderr, "usage: %s <elf>\n", argv[0]);
129	    return EXIT_FAILURE;
130	  }
131	  auto broker = cci_utils::broker{"global_broker"};
132	  cci::cci_register_broker(broker);
133	  return run_smoke<VSIM_CPU_INTERFACE_CLASS>(argv[1]);
134	} catch (const std::exception& e) {
135	  spdlog::error("dmi_smoke FAIL: exception: {}", e.what());
136	  return 99;
137	}
