1	/* handoff.elf is run under qemu-riscv64 (linux-user) AND vsim. linux-user
2	   refuses to map below MMAP_MIN_ADDR (typically 0x10000), so the program
3	   is linked above that. vsim's RAM (0x0..0x7FFFFFFF) covers it. */
4	
5	ENTRY(_start)
6	
7	SECTIONS {
8	    . = 0x10000;
9	    .text : { *(.text*) }
10	    /DISCARD/ : { *(.*) }
11	}
12

1	/* Place .text inside RAM_BASE..RAM_END (memory_map.h). Reset vector reads
2	   from the ELF entrypoint, which is _start. */
3	
4	ENTRY(_start)
5	
6	SECTIONS {
7	    . = 0x80;
8	    .text : { *(.text*) }
9	    /DISCARD/ : { *(.*) }
10	}
11

1	// Reads and validates a hybrid_state_v1 from a file produced by the QEMU
2	// plugin. Validation is the boundary check before any in-process JTAG poke.
3	
4	#include "hybrid/state_abi.h"
5	#include "hybrid/state_loader.hpp"
6	
7	#define DOCTEST_CONFIG_IMPLEMENT_WITH_MAIN
8	#include <doctest.h>
9	
10	#include <cstdio>
11	#include <cstring>
12	#include <filesystem>
13	#include <fstream>
14	#include <string>
