16	namespace {
17	auto unique_tmp_path(const char* tag) -> std::string
18	{
19	  auto p = std::filesystem::temp_directory_path()
20	           / (std::string{"vsim_state_"} + tag + "_"
21	              + std::to_string(::getpid()));
22	  std::filesystem::remove(p);
23	  return p.string();
24	}
25	
26	auto write_bytes(const std::string& path, const void* data, std::size_t n)
27	  -> void
28	{
29	  std::ofstream f(path, std::ios::binary | std::ios::trunc);
30	  f.write(static_cast<const char*>(data), static_cast<std::streamsize>(n));
31	}
32	
33	auto good_state() -> hybrid_state_v1
34	{
35	  hybrid_state_v1 s{};
36	  s.magic = HYBRID_STATE_MAGIC;
37	  s.version = HYBRID_STATE_VERSION;
38	  s.flags = HYBRID_FLAG_RV64;
39	  s.hart_id = 0;
40	  s.pc = 0x80001000ULL;
41	  s.priv = 3;
42	  for (int i = 0; i < 32; ++i) s.gpr[i] = 0xA0000000ULL + i;
43	  return s;
44	}
45	}  // namespace
46	
47	TEST_CASE("load_state returns the struct verbatim from a valid file")
48	{
49	  const auto path = unique_tmp_path("ok");
50	  const auto src = good_state();
51	  write_bytes(path, &src, sizeof(src));
52	
53	  hybrid::HybridState loaded = hybrid::load_state(path);
54	  CHECK(loaded.magic == HYBRID_STATE_MAGIC);
55	  CHECK(loaded.version == HYBRID_STATE_VERSION);
56	  CHECK(loaded.pc == 0x80001000ULL);
57	  CHECK(loaded.priv == 3);
58	  for (int i = 0; i < 32; ++i) CHECK(loaded.gpr[i] == 0xA0000000ULL + i);
59	  std::filesystem::remove(path);
60	}
61	
62	TEST_CASE("load_state rejects a missing file")
63	{
64	  const auto path = unique_tmp_path("missing");
65	  std::filesystem::remove(path);
66	  CHECK_THROWS(hybrid::load_state(path));
67	}
68	
69	TEST_CASE("load_state rejects a wrong-magic file")
70	{
71	  const auto path = unique_tmp_path("magic");
72	  auto s = good_state();
73	  s.magic = 0xDEADBEEFu;
74	  write_bytes(path, &s, sizeof(s));
75	  CHECK_THROWS(hybrid::load_state(path));
76	  std::filesystem::remove(path);
77	}
78	
79	TEST_CASE("load_state rejects a wrong-version file")
80	{
81	  const auto path = unique_tmp_path("version");
82	  auto s = good_state();
83	  s.version = HYBRID_STATE_VERSION + 1;
84	  write_bytes(path, &s, sizeof(s));
85	  CHECK_THROWS(hybrid::load_state(path));
86	  std::filesystem::remove(path);
87	}
