1	// Encodes the RISC-V Debug Module "Access Register" Abstract Command (cmdtype=0)
2	// per the Debug Spec 1.0. Pure bit-manipulation; no SystemC dependency.
3	
4	#include "hybrid/abstract_command.hpp"
5	
6	#define DOCTEST_CONFIG_IMPLEMENT_WITH_MAIN
