15	TEST_CASE("regno helpers map to spec ranges")
16	{
17	  CHECK(regno_csr(0x000) == 0x0000);
18	  CHECK(regno_csr(0x7C0) == 0x07C0);
19	  CHECK(regno_gpr(0)     == 0x1000);
20	  CHECK(regno_gpr(31)    == 0x101F);
21	  CHECK(regno_fpr(0)     == 0x1020);
22	  CHECK(regno_fpr(31)    == 0x103F);
