25	TEST_CASE("write 64-bit GPR x10 = 0x1000 with transfer set")
26	{
27	  // cmdtype=0 (zero), aarsize=3 (64-bit) at [22:20], transfer=1 at [17],
28	  // write=1 at [16], regno=0x100A in [15:0].
29	  const auto cmd = access_register_command(regno_gpr(10), AarSize::Bits64,
30	                                           /*write=*/true);
31	  CHECK(((cmd >> 24) & 0xff) == 0u);                // cmdtype = AccessRegister
32	  CHECK(((cmd >> 20) & 0x7) == uint32_t(AarSize::Bits64));
33	  CHECK(((cmd >> 17) & 0x1) == 1u);                 // transfer
34	  CHECK(((cmd >> 16) & 0x1) == 1u);                 // write
35	  CHECK((cmd & 0xffff)      == 0x100Au);            // regno
36	}
