1	// ResumeDriver translates a hybrid_state_v1 into a sequence of DMI register
2	// ops against the RISC-V Debug Module. The orchestration is testable in
3	// isolation by injecting a recording bus.
4	
5	#include "hybrid/abstract_command.hpp"
6	#include "hybrid/resume_driver.hpp"
7	#include "hybrid/state_abi.h"
8	
9	#define DOCTEST_CONFIG_IMPLEMENT_WITH_MAIN
10	#include <doctest.h>
11	
12	#include <cstdint>
13	#include <optional>
14	#include <vector>
15	
16	namespace {
17	
18	// DMI register addresses from RISC-V Debug Spec 1.0.
19	constexpr uint8_t kDmcontrol  = 0x10;
20	constexpr uint8_t kDmstatus   = 0x11;
21	constexpr uint8_t kAbstractcs = 0x16;
22	constexpr uint8_t kCommand    = 0x17;
23	constexpr uint8_t kData0      = 0x04;
24	constexpr uint8_t kData1      = 0x05;
25	
26	// CSR numbers from Debug Spec.
27	constexpr uint16_t kCsrDpc = 0x7B1;
28	
29	struct DmiOp
30	{
31	  enum class Kind
32	  {
33	    Write,
34	    Read,
35	  };
36	  Kind kind;
37	  uint8_t reg;
38	  uint32_t value;  // for writes only
39	};
40	
41	struct RecordingBus final : hybrid::DmiBus
42	{
43	  std::vector<DmiOp> ops;
44	
45	  // Test-controlled response values for reads.
46	  uint32_t dmstatus_value = 0;     // bit 9: allhalted, bit 17: allresumeack
47	  uint32_t abstractcs_value = 0;   // [12:8]: cmderr, [12]: busy
48	
49	  void write(uint8_t reg, uint32_t value) override
50	  {
51	    ops.push_back({DmiOp::Kind::Write, reg, value});
52	  }
53	
54	  auto read(uint8_t reg) -> uint32_t override
55	  {
56	    ops.push_back({DmiOp::Kind::Read, reg, 0});
57	    if (reg == kDmstatus) return dmstatus_value;
58	    if (reg == kAbstractcs) return abstractcs_value;
59	    return 0;
60	  }
61	};
62	
63	auto rv64_state(uint64_t pc, uint64_t x10) -> hybrid_state_v1
64	{
65	  hybrid_state_v1 s{};
66	  s.magic = HYBRID_STATE_MAGIC;
67	  s.version = HYBRID_STATE_VERSION;
68	  s.flags = HYBRID_FLAG_RV64;
69	  s.pc = pc;
70	  s.priv = 3;
71	  s.gpr[10] = x10;
72	  return s;
73	}
74	
75	auto find_write(const std::vector<DmiOp>& ops, uint8_t reg)
76	  -> std::vector<uint32_t>
77	{
78	  std::vector<uint32_t> values;
79	  for (const auto& op : ops)
80	    if (op.kind == DmiOp::Kind::Write && op.reg == reg)
81	      values.push_back(op.value);
82	  return values;
83	}
84	
85	auto count_writes_to(const std::vector<DmiOp>& ops, uint8_t reg) -> std::size_t
86	{
87	  std::size_t n = 0;
88	  for (const auto& op : ops)
89	    if (op.kind == DmiOp::Kind::Write && op.reg == reg) ++n;
90	  return n;
91	}
92	
93	}  // namespace
94	
95	TEST_CASE("resume halts the hart before any abstract command")
96	{
97	  RecordingBus bus;
98	  // dmstatus answers halted+resumeack so poll loops finish on the first read.
99	  bus.dmstatus_value = (1u << 9) | (1u << 17);
100	
101	  hybrid::ResumeDriver driver(bus);
102	  driver.resume(rv64_state(/*pc=*/0x80001000, /*x10=*/0xdeadbeef));
103	
104	  // The first write must prime dmactive (DM out of reset) BEFORE haltreq is
105	  // accepted; the second write must add haltreq while keeping dmactive set.
106	  REQUIRE(bus.ops.size() >= 2);
107	
108	  const auto& prime = bus.ops[0];
109	  CHECK(prime.kind == DmiOp::Kind::Write);
110	  CHECK(prime.reg == kDmcontrol);
111	  CHECK((prime.value & 1u) == 1u);                  // dmactive
112	  CHECK(((prime.value >> 31) & 1u) == 0u);          // haltreq NOT yet set
113	
114	  const auto& halt = bus.ops[1];
115	  CHECK(halt.kind == DmiOp::Kind::Write);
116	  CHECK(halt.reg == kDmcontrol);
117	  CHECK((halt.value & 1u) == 1u);                   // dmactive still set
118	  CHECK(((halt.value >> 31) & 1u) == 1u);           // haltreq
119	}
120	
121	TEST_CASE("resume programs every GPR via DATA0/DATA1 + COMMAND")
122	{
123	  RecordingBus bus;
124	  bus.dmstatus_value = (1u << 9) | (1u << 17);  // halted + resumeack
125	
126	  auto s = rv64_state(0x80001000, 0xdeadbeef);
127	  for (int i = 0; i < 32; ++i) s.gpr[i] = 0xa00000000ULL + i;
128	
129	  hybrid::ResumeDriver driver(bus);
130	  driver.resume(s);
131	
132	  // 32 commands targeting regnos 0x1000..0x101F, each preceded by DATA0/DATA1.
133	  std::vector<uint32_t> cmds;
134	  for (const auto& op : bus.ops)
135	    if (op.kind == DmiOp::Kind::Write && op.reg == kCommand)
136	      cmds.push_back(op.value);
137	
138	  // At least 32 GPR commands (more if FP/CSR are also written).
139	  CHECK(cmds.size() >= 32);
140	
141	  // First 32 commands cover GPRs in order, 64-bit, transfer=1, write=1.
142	  for (int i = 0; i < 32; ++i) {
143	    const auto expect =
144	      hybrid::access_register_command(hybrid::regno_gpr(i),
145	                                      hybrid::AarSize::Bits64, /*write=*/true);
146	    CHECK(cmds[i] == expect);
147	  }
148	}
149	
150	TEST_CASE("resume writes DPC = state.pc")
151	{
152	  RecordingBus bus;
153	  bus.dmstatus_value = (1u << 9) | (1u << 17);
154	
155	  constexpr uint64_t pc = 0x12345678'9ABCDEF0ULL;
156	  hybrid::ResumeDriver driver(bus);
157	  driver.resume(rv64_state(pc, 0));
158	
159	  // Look for the COMMAND write that targets CSR DPC (regno=0x7B1).
160	  std::vector<std::size_t> dpc_cmd_indices;
161	  for (std::size_t i = 0; i < bus.ops.size(); ++i) {
162	    const auto& op = bus.ops[i];
163	    if (op.kind == DmiOp::Kind::Write && op.reg == kCommand
164	        && (op.value & 0xffffu) == kCsrDpc) {
165	      dpc_cmd_indices.push_back(i);
166	    }
167	  }
168	  REQUIRE(dpc_cmd_indices.size() == 1);
169	
170	  // Immediately preceding writes must set DATA0=low32(pc), DATA1=high32(pc).
171	  const auto cmd_idx = dpc_cmd_indices[0];
172	  REQUIRE(cmd_idx >= 2);
173	  const auto& d0 = bus.ops[cmd_idx - 2];
174	  const auto& d1 = bus.ops[cmd_idx - 1];
175	  CHECK(d0.kind == DmiOp::Kind::Write);
176	  CHECK(d0.reg == kData0);
177	  CHECK(d0.value == uint32_t(pc & 0xffffffffu));
178	  CHECK(d1.kind == DmiOp::Kind::Write);
179	  CHECK(d1.reg == kData1);
180	  CHECK(d1.value == uint32_t((pc >> 32) & 0xffffffffu));
181	}
182	
183	TEST_CASE("resume issues resumereq after register programming")
184	{
185	  RecordingBus bus;
186	  bus.dmstatus_value = (1u << 9) | (1u << 17);
187	
188	  hybrid::ResumeDriver driver(bus);
189	  driver.resume(rv64_state(0x80001000, 0));
190	
191	  // The last DMCONTROL write must clear haltreq and set resumereq.
192	  const auto dmctl_writes = find_write(bus.ops, kDmcontrol);
193	  REQUIRE(dmctl_writes.size() >= 2);
194	  const auto last = dmctl_writes.back();
195	  CHECK((last & 1u) == 1u);                  // dmactive still on
196	  CHECK(((last >> 31) & 1u) == 0u);          // haltreq cleared
197	  CHECK(((last >> 30) & 1u) == 1u);          // resumereq set
198	}
199	
200	TEST_CASE("resume polls DMSTATUS for halted before programming registers")
201	{
202	  RecordingBus bus;
203	  bus.dmstatus_value = (1u << 9) | (1u << 17);
204	
205	  hybrid::ResumeDriver driver(bus);
206	  driver.resume(rv64_state(0x80001000, 0));
207	
208	  // At least one DMSTATUS read happened, and it occurred before the first
209	  // DATA0/DATA1 write.
210	  std::optional<std::size_t> first_dmstatus_read;
211	  std::optional<std::size_t> first_data_write;
212	  for (std::size_t i = 0; i < bus.ops.size(); ++i) {
213	    const auto& op = bus.ops[i];
214	    if (op.kind == DmiOp::Kind::Read && op.reg == kDmstatus
215	        && !first_dmstatus_read)
216	      first_dmstatus_read = i;
217	    if (op.kind == DmiOp::Kind::Write && op.reg == kData0 && !first_data_write)
218	      first_data_write = i;
219	  }
220	  REQUIRE(first_dmstatus_read);
221	  REQUIRE(first_data_write);
222	  CHECK(*first_dmstatus_read < *first_data_write);
223	}
224	
225	TEST_CASE("resume rejects a state with wrong magic")
226	{
227	  RecordingBus bus;
228	  hybrid::ResumeDriver driver(bus);
229	
230	  hybrid_state_v1 bad{};
231	  bad.version = HYBRID_STATE_VERSION;
232	  bad.magic = 0xDEADBEEFu;
233	  CHECK_THROWS(driver.resume(bad));
234	}
235	
236	TEST_CASE("resume issues exactly one COMMAND per programmed register")
237	{
238	  RecordingBus bus;
239	  bus.dmstatus_value = (1u << 9) | (1u << 17);
240	
241	  hybrid::ResumeDriver driver(bus);
242	  driver.resume(rv64_state(0x80001000, 0));
243	
244	  // 32 GPRs + DPC at minimum. We do not yet program FPR/CSR/V; bound below.
245	  CHECK(count_writes_to(bus.ops, kCommand) >= 33u);
246	}
