1	// End-to-end of the file-only path: read a state file from disk and drive a
2	// DMI bus through ResumeDriver. The bus is a recording mock; the SystemC and
3	// AHB layers are exercised in the actual simulator integration.
4	
5	#include "hybrid/resume_driver.hpp"
6	#include "hybrid/resume_from_qemu.hpp"
7	#include "hybrid/state_abi.h"
8	
9	#define DOCTEST_CONFIG_IMPLEMENT_WITH_MAIN
10	#include <doctest.h>
11	
12	#include <cstdio>
13	#include <filesystem>
14	#include <fstream>
15	#include <string>
16	#include <vector>
17	
18	namespace {
19	
20	constexpr uint8_t kDmcontrol = 0x10;
21	constexpr uint8_t kCommand   = 0x17;
22	
23	constexpr uint16_t kCsrDpc = 0x7B1;
24	
25	struct RecordingBus final : hybrid::DmiBus
26	{
27	  struct Op
28	  {
29	    bool is_write;
30	    uint8_t reg;
31	    uint32_t value;
32	  };
33	  std::vector<Op> ops;
34	  uint32_t dmstatus_value = (1u << 9) | (1u << 17);
35	  uint32_t abstractcs_value = 0;
36	
37	  void write(uint8_t r, uint32_t v) override
38	  {
39	    ops.push_back({true, r, v});
40	  }
41	  auto read(uint8_t r) -> uint32_t override
42	  {
43	    ops.push_back({false, r, 0});
44	    if (r == 0x11) return dmstatus_value;
45	    if (r == 0x16) return abstractcs_value;
46	    return 0;
47	  }
48	};
49	
50	auto unique_tmp_path(const char* tag) -> std::string
51	{
52	  auto p = std::filesystem::temp_directory_path()
53	           / (std::string{"vsim_resume_"} + tag + "_"
54	              + std::to_string(::getpid()));
55	  std::filesystem::remove(p);
56	  return p.string();
57	}
58	
59	auto write_state_file(const std::string& path, const hybrid_state_v1& s)
60	  -> void
61	{
62	  std::ofstream f(path, std::ios::binary | std::ios::trunc);
63	  f.write(reinterpret_cast<const char*>(&s),
64	          static_cast<std::streamsize>(sizeof(s)));
65	}
66	
67	}  // namespace
68	
69	TEST_CASE("resume_from_qemu loads file then drives bus to set DPC")
70	{
71	  hybrid_state_v1 s{};
72	  s.magic = HYBRID_STATE_MAGIC;
73	  s.version = HYBRID_STATE_VERSION;
74	  s.flags = HYBRID_FLAG_RV64;
75	  s.pc = 0xDEADC0DE'BEEFFEEDULL;
76	
77	  const auto path = unique_tmp_path("ok");
78	  write_state_file(path, s);
79	
80	  RecordingBus bus;
81	  hybrid::resume_from_qemu(path, bus);
82	
83	  // The first DMCONTROL write primes dmactive (without haltreq); the
84	  // second DMCONTROL write requests halt.
85	  REQUIRE(bus.ops.size() >= 2);
86	  CHECK(bus.ops[0].is_write);
87	  CHECK(bus.ops[0].reg == kDmcontrol);
88	  CHECK((bus.ops[0].value & 1u) == 1u);
89	  CHECK(((bus.ops[0].value >> 31) & 1u) == 0u);
90	
91	  CHECK(bus.ops[1].is_write);
92	  CHECK(bus.ops[1].reg == kDmcontrol);
93	  CHECK(((bus.ops[1].value >> 31) & 1u) == 1u);
94	
95	  // A COMMAND write targeting CSR DPC (regno=0x7B1) must occur.
96	  bool saw_dpc_command = false;
97	  for (const auto& op : bus.ops) {
98	    if (op.is_write && op.reg == kCommand && (op.value & 0xffffu) == kCsrDpc) {
99	      saw_dpc_command = true;
100	      break;
101	    }
102	  }
103	  CHECK(saw_dpc_command);
104	
105	  std::filesystem::remove(path);
106	}
107	
108	TEST_CASE("resume_from_qemu propagates load errors")
109	{
110	  RecordingBus bus;
111	  CHECK_THROWS(hybrid::resume_from_qemu("/no/such/file/here", bus));
112	  CHECK(bus.ops.empty());
113	}
