132	      std::optional<uint64_t> kanata_loop_start{};
133	      std::optional<uint64_t> kanata_loop_end{};
134	      uint64_t kanata_loop_skip = 0;
135	      uint64_t kanata_loop_record = 1;
136	      std::vector<std::string> reset_vectors{};
137	      bool continue_ctx = false;
138	      bool save_ctx = false;
139	      std::string context_dir = "./saved_ctx/";

253	
254	#ifndef VSIMSAVABLE
255	  if (args.save_ctx || args.continue_ctx || args.context_dir != "./saved_ctx/")
256	  {
257	    spdlog::critical(
258	      "--save, --continue, and --context-dir require VSIMSAVABLE build");
259	    std::exit(EXIT_FAILURE);
260	  }
261	#endif
262	
263	  if (!args.resume_from_qemu.empty() && args.continue_ctx)
264	    throw std::runtime_error(
265	      "--resume-from-qemu and --continue are mutually exclusive");
266	
267	  // Pre-flight: validate the state file before any simulation work begins.
268	  if (!args.resume_from_qemu.empty())
269	    (void) hybrid::load_state(args.resume_from_qemu);
270	
271	  print_version();
272	
273	  // systemc and cci init
274	  auto broker = cci_utils::broker{"global_broker"};
275	  cci::cci_register_broker(broker);
276	
277	  const auto time_resolution = sc_core::sc_get_time_resolution();
278	  spdlog::debug("Using time resolution: {}", time_resolution.to_string());
279	
280	  std::optional<MmapBacking> shared_ram;
281	  if (!args.shared_mem_path.empty()) {
282	    if (args.shared_mem_size == 0)
283	      throw std::runtime_error(
284	        "--shared-mem-path requires --shared-mem-size > 0");
285	    shared_ram.emplace(args.shared_mem_path, args.shared_mem_size);
286	  } else if (args.shared_mem_size != 0) {
287	    throw std::runtime_error(
288	      "--shared-mem-size requires --shared-mem-path");
289	  }
290	
291	  // run simulation
292	  const auto do_sim = [&]<typename CPU>() -> int {
293	    Simulator<CPU> sim{
294	      "sim", shared_ram ? shared_ram->span() : std::span<uint8_t>{}};
295	
296	    if (args.memmap) {
297	      sim.platform.interconnect.dump_region();
298	      return 0;
299	    }
300	
301	    sim.set_mem_latency(args.mem_latency);
302	
303	    if (!args.ilm_file.empty())
304	      sim.load_image(args.ilm_file, MEM_TYPE::ILM);
305	
306	    if (!args.dlm_file.empty())
307	      sim.load_image(args.dlm_file, MEM_TYPE::DLM);
308	
309	    // End of elaboration
310	    sc_core::sc_start(sc_core::SC_ZERO_TIME);
311	
312	    const auto t0 = std::chrono::steady_clock::now();
313	
314	    if (!args.waveform_file.empty())
315	      sim.enable_waveform(args.waveform_file);
316	
317	    if (!args.pc_trace_file.empty())
318	      sim.enable_pc_trace(args.pc_trace_file);
319	
320	    if (!args.kanata_file.empty() && !args.clarity_file.empty())
321	      throw std::runtime_error("--kanata and --clarity are mutually exclusive");
322	
323	    std::optional<kanata::LoopGate> loop_gate;
324	    if (args.kanata_loop_start.has_value()
325	        != args.kanata_loop_end.has_value())
326	      throw std::runtime_error(
327	        "--kanata-loop-start and --kanata-loop-end must be specified together");
328	    if (args.kanata_loop_start.has_value()) {
329	      if (args.kanata_file.empty() && args.clarity_file.empty())
330	        throw std::runtime_error(
331	          "--kanata-loop-* requires --kanata or --clarity");
332	      if (args.kanata_loop_record == 0)
333	        throw std::runtime_error("--kanata-loop-record must be >= 1");
334	      loop_gate = kanata::LoopGate{*args.kanata_loop_start,
335	                                   *args.kanata_loop_end,
336	                                   args.kanata_loop_skip,
337	                                   args.kanata_loop_record};
338	    }
339	
340	    if (!args.kanata_file.empty())
341	      sim.enable_kanata(args.kanata_file, args.objdump_file, loop_gate);
342	
343	    if (!args.clarity_file.empty())
344	      sim.enable_clarity(args.clarity_file, args.objdump_file, loop_gate);
345	
346	    if (!args.elf_file.empty() && !args.continue_ctx)
347	      sim.load_elf(args.elf_file);
348	
349	    // Apply per-hart reset vector overrides (after load_elf sets defaults)
350	    for (const auto& s: args.reset_vectors) {
351	      auto [hart, addr] = parse_reset_vector(s);
352	      if (hart) {
353	        sim.set_reset_vector(*hart, addr);
354	      } else {
355	        for (size_t i = 0; i < sim.platform.reset_vector.size(); ++i)
356	          sim.set_reset_vector(i, addr);
357	      }
358	    }
359	
360	    if (args.continue_ctx)
361	      spdlog::info("You're resuming program from the given context");
362	
363	    if (args.jtag_port)
364	      sim.init_debug_port(args.jtag_port.value());
365	
366	    if (!args.resume_from_qemu.empty())
367	      sim.enable_resume_from_qemu(args.resume_from_qemu);
368	
369	    if (!args.jtag_port && args.elf_file.empty() && !args.continue_ctx
370	        && args.resume_from_qemu.empty())
371	      throw std::runtime_error(
372	        "Required arg : program, --jtag-port, or --resume-from-qemu");
373	
374	    if (args.continue_ctx || args.save_ctx) {
375	      std::string_view s = args.context_dir;
376	      if (std::filesystem::exists(s) && !std::filesystem::is_directory(s))
377	        throw std::runtime_error("Error: Path " + std::string{s}
378	                                 + " exists but is not a directory.");
379	      if (!std::filesystem::exists(s)) {
380	        try {
381	          std::filesystem::create_directories(s);
382	        } catch (const std::filesystem::filesystem_error& e) {
383	          throw std::runtime_error(std::string{"Failed to create directory: "}
384	                                   + e.what());
385	        }
386	      }
387	      sim.context_config = {args.save_ctx, args.continue_ctx, args.context_dir};
388	    }
389	
390	    sim.reset();
391	
392	    sim.apply_resume_from_qemu();

160	    }
161	
162	#if _NDS_IOCP_NUM > 0
163	    iocp_master.protocol_engine.clk_i.bind(platform.clk);
164	    iocp_master.socket.bind(cpu.iocp_bfm.tsckt);
165	#endif // _NDS_IOCP_NUM
166	  }
