182	  // Drive the live Debug Module to load architectural state from a QEMU-side
183	  // snapshot. Must be called between reset() and run(), so the CPU is out of
184	  // reset and the SC kernel has a clean slate.
185	  void apply_resume_from_qemu()
186	  {
187	    if (resume_from_qemu_path_.empty()) return;
188	    hybrid::SystemCDmiBus<PLATFORM::dmi_addr_width, PLATFORM::dmi_data_width>
189	      bus{platform.dmi, platform.clk.period()};
190	    hybrid::resume_from_qemu(resume_from_qemu_path_, bus);
191	    resume_from_qemu_path_.clear();
192	  }
